 75→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 76→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 77→    val totalFields = accumulator + fieldsCount
 78→    val superClass = superclass ?: return totalFields
 79→    return superClass.fieldsCount(totalFields)
 80→}
