package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

/**
 * Test that verifies that recoverStackTrace doesn't cause extra nesting of exceptions.
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/2055
 */
class StackTraceRecoveryNestedExceptionCauseTest : TestBase() {

    /**
     * Exception with string constructor first - this was the original bug case where
     * the wrong constructor was being selected, causing an extra level of nesting.
     */
    class NestedExceptionStringFirst : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    /**
     * Exception with throwable constructor first - this used to work correctly.
     */
    class NestedExceptionThrowableFirst : RuntimeException {
        constructor(cause: Throwable) : super(cause)
        constructor(message: String) : super(message)
        constructor() : super()
    }

    /**
     * Tests that when throwing an exception with a cause, the cause is preserved
     * correctly without extra nesting, regardless of constructor order.
     */
    @Test
    fun testNestedExceptionStringFirst() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionStringFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionStringFirst, "Expected NestedExceptionStringFirst but got ${ex::class}")
        // The cause should be IllegalStateException, NOT another NestedExceptionStringFirst
        val cause = ex.cause
        assertTrue(cause is IllegalStateException, "Expected IllegalStateException cause but got ${cause?.let { it::class }}")
        assertEquals("ERROR", cause.message)
    }

    @Test
    fun testNestedExceptionThrowableFirst() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionThrowableFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionThrowableFirst, "Expected NestedExceptionThrowableFirst but got ${ex::class}")
        // The cause should be IllegalStateException
        val cause = ex.cause
        assertTrue(cause is IllegalStateException, "Expected IllegalStateException cause but got ${cause?.let { it::class }}")
        assertEquals("ERROR", cause.message)
    }

    /**
     * Tests with withContext to ensure stack trace recovery with nested exceptions works.
     */
    @Test
    fun testNestedExceptionWithContext() = runTest {
        val result = runCatching {
            withContext(Dispatchers.Default) {
                throw NestedExceptionStringFirst(IllegalStateException("WITH_CONTEXT_ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionStringFirst)
        // During stack trace recovery, the cause will be the original exception with the same type
        // The key is that there should not be triple nesting
        var depth = 0
        var current: Throwable? = ex
        while (current != null) {
            depth++
            current = current.cause
        }
        // Should be at most 3: recovered exception -> original exception -> IllegalStateException cause
        assertTrue(depth <= 3, "Exception nesting too deep: $depth levels")
    }
}
"}

